using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            using var transaction = db.Database.BeginTransaction();
            db.Database.Migrate();
            transaction.Commit();
        });
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // EF Core 9 throws if Migrate() is called inside a user transaction.
        // Migrate manages its own transactions internally.
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

